                    console.log('All leave balances updated successfully in database');

                  } catch (error) {
                    console.error('Error updating leave balances:', error);
                    // Revert to previous state if update fails
                    console.log('Reverting to previous state...');
                    fetchLeaveBalances();
                  }
                }}
              />
            </div>
          </div>
        </div>
      </main>
    </div>
  );
}

export default App;
